// Parse incoming request and build Grok API prompts
const input = $input.first().json.body;

const topic = input.topic || 'AI trends';
const modules = (input.modules || 'trends,stats,experts,social').split(',');
const depth = input.depth || 'standard';
const language = input.language || 'EN';
const brand = input.brand || 'neutral';

const models = {
  quick: 'grok-3-fast',
  standard: 'grok-4.20-reasoning',
  deep: 'grok-4.20-reasoning'
};

const langInstructions = {
  DE: 'Respond entirely in German. Search in both German and English but present all findings in German.',
  EN: 'Respond entirely in English.',
  BOTH: 'Search in both German and English. Present findings in the primary language.'
};

const brandContexts = {
  mmind: 'Context: Research for MMIND.ai — AI integration consultancy targeting SMEs in DACH.',
  flowstate: 'Context: Research for FlowState Cyclist — executives using cycling and AI for leadership.',
  abcc: 'Context: Research for Association of British Cycling Coaches.',
  kaizen: 'Context: Research for Kaizen Institute — continuous improvement.',
  neutral: ''
};

const modulePrompts = {
  trends: 'Search for the latest developments, news, and emerging trends about ' + topic + ' from the past 30 days. For each finding, provide: key insight, source name, source URL, publication date.',
  stats: 'Find current statistics, survey data, market figures about ' + topic + '. Prioritize institutional data. For each: exact figure, what it measures, source with URL, date.',
  experts: 'Find notable expert opinions and thought leader statements about ' + topic + '. For each: name and title, key statement, source/platform, URL.',
  social: 'Search X/Twitter for engaging posts about ' + topic + ' (past 14 days). Also find top LinkedIn posts. For each: author, key message, engagement, URL.',
  science: 'Search for peer-reviewed research papers about ' + topic + '. For each: title, authors, journal, year, key finding, DOI/URL.',
  competitors: 'Analyze competitive landscape around ' + topic + '. For each insight: company, action, source URL, date.'
};

// Create one item per module for parallel execution
const items = modules.map(mod => ({
  json: {
    module: mod,
    topic: topic,
    model: models[depth],
    prompt: (brandContexts[brand] || '') + '\n\n' + (langInstructions[language] || langInstructions.EN) + '\n\n' + (modulePrompts[mod] || ''),
    depth: depth,
    language: language,
    brand: brand
  }
}));

return items;

// Extract text and citations from Grok response
const items = $input.all();
const results = [];

for (const item of items) {
  const response = item.json;
  const module = item.json.module || 'unknown';
  let textParts = [];
  let citations = [];

  const output = response.output || response.content || [];
  for (const block of output) {
    if (block.type === 'message') {
      for (const cb of (block.content || [])) {
        if (cb.type === 'output_text') {
          textParts.push(cb.text || '');
          for (const ann of (cb.annotations || [])) {
            if (ann.type === 'url_citation') {
              citations.push({ title: ann.title || '', url: ann.url || '' });
            }
          }
        }
      }
    } else if (block.type === 'text') {
      textParts.push(block.text || '');
    }
  }

  results.push({
    json: {
      module: module,
      text: textParts.join('\n'),
      citations: citations,
      citationCount: citations.length
    }
  });
}

return results;

// Assemble all module results into a Research Brief
const items = $input.all();
const today = new Date().toISOString().split('T')[0];

let brief = `# Research Brief\n**Date:** ${today}\n\n`;
let totalCitations = 0;

for (const item of items) {
  const { module, text, citations, citationCount } = item.json;
  const label = {
    trends: 'Trends & News',
    stats: 'Statistics & Data',
    experts: 'Expert Voices',
    social: 'Social Pulse',
    science: 'Scientific Sources',
    competitors: 'Competitor/Market Intelligence'
  }[module] || module;

  brief += `## ${label}\n\n${text}\n\n`;

  if (citations && citations.length > 0) {
    brief += `### Sources (${citations.length})\n`;
    citations.forEach((c, i) => {
      brief += `${i+1}. [${c.title}](${c.url})\n`;
    });
    brief += '\n';
    totalCitations += citations.length;
  }
}

brief += `---\n**Total sources:** ${totalCitations}\n`;

return [{ json: { brief: brief, totalCitations: totalCitations } }];
